const cors = require('cors');
const allowed = new Set(['https://app.example.com']);
app.use(cors({
  origin: (origin, cb) => (!origin || allowed.has(origin)) ? cb(null, true) : cb(new Error('CORS')),
  methods: ['GET'],
}));
```

### 5. `app.listen` binds to all interfaces with a hard-coded port (A05) — **Low**
